                    new DialogueChoice { text = "\"I can't stop the verdict — it's ten thousand years too old for me to undo from here. But I can *witness* it. I can be the one who *remembers* that the first Faithless pulled Calla from the river. You won't go unwitnessed.\"", nextNodeId = "witness", effects = new[] { new FlagClause { key = "act3.first_faithless_remembered", op = FlagOp.SetTrue } } },
